import { describe, it, expect } from 'vitest';
import type { User, UpdateUserInput } from '../../src/models/user.js';
import {
  validateUserExists,
  validateEmailNotTaken,
  validateEmailNotInUse,
  detectUserChanges,
} from '../../src/validators/user.validator.js';

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-0001',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

describe('user.validator', () => {
  describe('validateUserExists', () => {
    it('should not throw when user exists', () => {
      const user = makeUser();
      expect(() => validateUserExists(user, 'user-0001')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-9999')).toThrow(
        'User not found: user-9999',
      );
    });
  });

  describe('validateEmailNotTaken', () => {
    it('should not throw when no existing user has the email', () => {
      expect(() => validateEmailNotTaken(undefined, 'new@example.com')).not.toThrow();
    });

    it('should throw when a user with the email already exists', () => {
      const existing = makeUser();
      expect(() => validateEmailNotTaken(existing, 'alice@example.com')).toThrow(
        'User with email alice@example.com already exists',
      );
    });
  });

  describe('validateEmailNotInUse', () => {
    it('should not throw when no existing user has the email', () => {
      expect(() => validateEmailNotInUse(undefined, 'new@example.com')).not.toThrow();
    });

    it('should throw when the email is already in use', () => {
      const existing = makeUser();
      expect(() => validateEmailNotInUse(existing, 'alice@example.com')).toThrow(
        'Email alice@example.com is already in use',
      );
    });
  });

  describe('detectUserChanges', () => {
    it('should detect name change', () => {
      const existing = makeUser();
      const input: UpdateUserInput = { name: 'Alice Smith' };

      expect(detectUserChanges(input, existing)).toEqual(['name']);
    });

    it('should detect email change', () => {
      const existing = makeUser();
      const input: UpdateUserInput = { email: 'newalice@example.com' };

      expect(detectUserChanges(input, existing)).toEqual(['email']);
    });

    it('should detect role change', () => {
      const existing = makeUser();
      const input: UpdateUserInput = { role: 'admin' };

      expect(detectUserChanges(input, existing)).toEqual(['role']);
    });

    it('should detect multiple changes', () => {
      const existing = makeUser();
      const input: UpdateUserInput = { name: 'Bob', email: 'bob@example.com', role: 'admin' };

      expect(detectUserChanges(input, existing)).toEqual(['name', 'email', 'role']);
    });

    it('should return empty array when nothing changed', () => {
      const existing = makeUser();
      const input: UpdateUserInput = {};

      expect(detectUserChanges(input, existing)).toEqual([]);
    });

    it('should return empty array when same values are provided', () => {
      const existing = makeUser();
      const input: UpdateUserInput = {
        name: existing.name,
        email: existing.email,
        role: existing.role,
      };

      expect(detectUserChanges(input, existing)).toEqual([]);
    });
  });
});

import { describe, it, expect } from 'vitest';
import type { Order, OrderItem, OrderStatus } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';
import {
  isValidStatusTransition,
  validateStatusTransition,
  validateOrderHasItems,
  validateOrderUserExists,
  validateOrderExists,
} from '../../src/validators/order.validator.js';

function makeOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'order-0001',
    userId: 'user-0001',
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    total: 10,
    status: 'pending',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-0001',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

describe('order.validator', () => {
  describe('isValidStatusTransition', () => {
    it('should allow pending → confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending → cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed → shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed → cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped → delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending → delivered (skip states)', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending → shipped (skip states)', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered → anything (terminal)', () => {
      expect(isValidStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidStatusTransition('delivered', 'confirmed')).toBe(false);
      expect(isValidStatusTransition('delivered', 'shipped')).toBe(false);
      expect(isValidStatusTransition('delivered', 'cancelled')).toBe(false);
    });

    it('should reject cancelled → anything (terminal)', () => {
      expect(isValidStatusTransition('cancelled', 'pending')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'confirmed')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'shipped')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'delivered')).toBe(false);
    });

    it('should reject shipped → confirmed (backward)', () => {
      expect(isValidStatusTransition('shipped', 'confirmed')).toBe(false);
    });
  });

  describe('validateStatusTransition', () => {
    it('should not throw for valid transitions', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
      expect(() => validateStatusTransition('confirmed', 'shipped')).not.toThrow();
      expect(() => validateStatusTransition('shipped', 'delivered')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should throw for terminal state transitions', () => {
      expect(() => validateStatusTransition('cancelled', 'confirmed')).toThrow(
        'Invalid status transition: cancelled -> confirmed',
      );
    });
  });

  describe('validateOrderHasItems', () => {
    it('should not throw when items array has elements', () => {
      const items: OrderItem[] = [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
      ];
      expect(() => validateOrderHasItems(items)).not.toThrow();
    });

    it('should not throw when items array has multiple elements', () => {
      const items: OrderItem[] = [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        { productId: 'p2', name: 'Gadget', quantity: 2, unitPrice: 20 },
      ];
      expect(() => validateOrderHasItems(items)).not.toThrow();
    });

    it('should throw when items array is empty', () => {
      expect(() => validateOrderHasItems([])).toThrow(
        'Order must have at least one item',
      );
    });
  });

  describe('validateOrderUserExists', () => {
    it('should not throw when user exists', () => {
      const user = makeUser();
      expect(() => validateOrderUserExists(user, 'user-0001')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateOrderUserExists(undefined, 'user-9999')).toThrow(
        'User not found: user-9999',
      );
    });
  });

  describe('validateOrderExists', () => {
    it('should not throw when order exists', () => {
      const order = makeOrder();
